<template>
  <div class="index_sum">
    <van-row class="index">
      <van-col class="index_a" span="2"></van-col>
      <van-col class="index_b" span="20">
        <div class="my_content">
          <img src="../../assets/tx.png" alt="" />
          <div @click="login(lims_name ? lims_name : '请先登入')">
            <p>{{ lims_name ? lims_name : "请先登入" }}</p>
            <span>{{ userid ? userid : "***" }}</span>
          </div>
        </div>
      </van-col>
      <van-col class="index_c" span="2"></van-col>
    </van-row>
    <van-row class="my_fei">
      <van-col span="2"> </van-col>
      <van-col span="20" class="index_show">
        <van-col span="12" class="my_two my_border_r" @click="myista('1')">
          <main>
            <p>{{ currentEntrustNum }}</p>
            <span>我的委托</span>
          </main>
        </van-col>
        <van-col class="my_border_l my_two" span="12" @click="myhistory('2')">
          <main>
            <p>{{ historyEntrustNum }}</p>
            <span>物流信息</span>
          </main>
        </van-col>
        <van-col span="2"> </van-col>
      </van-col>
    </van-row>
    <div class="index_main">
      <van-cell
        title="地址"
        icon="location-o"
        is-link
        size="large"
        @click="goPage('addresslist')"
      >
      </van-cell>
      <van-cell
        title="分享"
        icon="share-o"
        is-link
        size="large"
        @click="goPage()"
      >
      </van-cell>
      <van-cell
        title="帮助"
        icon="comment-o"
        is-link
        size="large"
        @click="goPage()"
      >
      </van-cell>
      <van-cell
        title="设置"
        icon="setting-o"
        is-link
        size="large"
        @click="goPage('setuplist')"
      >
      </van-cell>
    </div>
  </div>
</template>

<script>
import { mapState } from "vuex";
import { getcount } from "../../utils/http/api";
import { Toast } from "vant";
export default {
  name: "index",
  data() {
    return {
      currentEntrustNum: 0,
      historyEntrustNum: 0,
    };
  },
  computed: {
    ...mapState(["userid", "lims_name", "adminId"]),
  },
  created() {
    getcount(this.adminId).then((res) => {
      // console.log(res);
      this.currentEntrustNum = res.data.data.currentEntrustNum;
      this.historyEntrustNum = res.data.data.historyEntrustNum;
    });
  },
  methods: {
    login(value) {
      if (value === "请先登入") {
        this.$router.push({ name: "login" });
      } else {
        this.$router.push({ name: "setuplist" });
      }
    },
    myista(type) {
      this.$router.push({ name: "myista", query: { type } });
    },
    myhistory(type) {
      Toast("未开通！！！");
      return;
      this.$router.push({ name: "myista", query: { type } });
    },
    goPage(value) {
      if (value) {
        this.$router.push({ name: value });
      } else {
        Toast("未开通！！！");
        return;
      }
    },
  },
};
</script>

<style lang="less">
.index_sum {
  height: 13.34rem;
  background: @gray-2;
}
.index {
  background: @blue;
  background-image: url("../../assets/index/user.png");
  background-size: 100% 100%;
  height: 3.5rem;
  .index_a {
    height: 100%;
  }
  .index_b {
    padding: 10px;
    box-sizing: border-box;

    height: 100%;
    display: flex;
    align-items: center;
  }
}
.my_content {
  height: 1rem;
  display: flex;

  img {
    width: 1rem;
    height: 1rem;
    border-radius: 50%;
    background: rgb(255, 255, 255);
    // border: 2px solid #1471ce;
  }
  div {
    display: flex;
    flex-direction: column;
    justify-content: center;
    margin-left: 0.2rem;
  }
  p:nth-child(1) {
    font-size: 0.32rem;
    font-weight: 600;
    color: white;
  }
  span:nth-child(2) {
    font-size: 0.24rem;
    color: white;
  }
}
.my_border_l {
  // border-left: 1px solid black;
  border-top-right-radius: 0.4rem;
  border-bottom-right-radius: 0.4rem;
}
.my_border_r {
  border-top-left-radius: 0.4rem;
  border-bottom-left-radius: 0.4rem;
}
.index_show {
  border-radius: 0.4rem;
  //   box-shadow: 1px 1px 1px 1px black;
  background-image: url("../../assets/index/ista.png");
  background-size: 100% 100%;
}
.my_two {
  height: 1.3rem;
  // background: #282c3b;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0.2rem;
  box-sizing: border-box;
  main {
    width: 2rem;
    height: 1.2rem;

    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    p {
      font-size: 0.4rem;
      // font-weight: 600;

      color: white;
    }
    span {
      font-size: 0.24rem;
      // font-size: 0.32rem;

      font-weight: 550;
      color: white;
    }
  }
}
.my_fei {
  position: fixed;
  top: 2.5rem;
  width: 7.5rem;
}
.index_main {
  margin: 0.2rem;
  margin-top: 0.6rem;
  padding: 0.2rem;
  box-sizing: border-box;
  background: white;
  border-radius: 0.4rem;
}
.custom-title {
  margin-right: 4px;
  vertical-align: middle;
}

.search-icon {
  font-size: 16px;
  line-height: inherit;
}
</style>